// Generated by OrchestKit Claude Plugin
// Created: 2026-03-14

export type CustomerTier = 'standard' | 'silver' | 'gold' | 'platinum';

export interface Promotion {
  code: string;
  discountPercent: number;
  minOrderTotal?: number;
  expiresAt?: Date;
}

export interface PricingResult {
  originalTotal: number;
  discountAmount: number;
  finalTotal: number;
  appliedDiscounts: string[];
}

export interface LoyaltyApiClient {
  getCustomerTier(customerId: string): Promise<CustomerTier>;
}

// Tier discount rates
const TIER_DISCOUNTS: Record<CustomerTier, number> = {
  standard: 0,
  silver: 0.05,
  gold: 0.10,
  platinum: 0.15,
};

// Volume discount thresholds
const VOLUME_TIERS = [
  { threshold: 500, rate: 0.10 },
  { threshold: 100, rate: 0.05 },
];

export class PricingService {
  constructor(private readonly loyaltyApi: LoyaltyApiClient) {}

  async calculatePrice(
    customerId: string,
    orderTotal: number,
    promotions: Promotion[] = [],
    now: Date = new Date(),
  ): Promise<PricingResult> {
    if (orderTotal < 0) throw new Error('orderTotal must be non-negative');

    let tier: CustomerTier = 'standard';
    try {
      tier = await this.loyaltyApi.getCustomerTier(customerId);
    } catch {
      // Degrade gracefully — treat as standard
      tier = 'standard';
    }

    const appliedDiscounts: string[] = [];
    let totalRate = 0;

    // Tier discount
    const tierRate = TIER_DISCOUNTS[tier];
    if (tierRate > 0) {
      totalRate += tierRate;
      appliedDiscounts.push(`tier:${tier}`);
    }

    // Volume discount (best bracket only)
    const volumeTier = VOLUME_TIERS.find((v) => orderTotal >= v.threshold);
    if (volumeTier) {
      totalRate += volumeTier.rate;
      appliedDiscounts.push(`volume:${volumeTier.threshold}`);
    }

    // Active promotions
    for (const promo of promotions) {
      if (promo.expiresAt && promo.expiresAt <= now) continue;
      if (promo.minOrderTotal !== undefined && orderTotal < promo.minOrderTotal) continue;
      totalRate += promo.discountPercent / 100;
      appliedDiscounts.push(`promo:${promo.code}`);
    }

    // Cap total discount at 50%
    totalRate = Math.min(totalRate, 0.5);

    const discountAmount = Math.round(orderTotal * totalRate * 100) / 100;
    const finalTotal = Math.round((orderTotal - discountAmount) * 100) / 100;

    return { originalTotal: orderTotal, discountAmount, finalTotal, appliedDiscounts };
  }
}
